#include <stdio.h>
#define N 3

float calculate_edf_utilization(float exec[], float period[], int n) {
    float total = 0.0f;
    for (int i = 0; i < n; i++) {
        total += exec[i] / period[i];
    }
    return total;
}

int main(void) {
    float exec[]   = {3.0f, 1.0f, 2.0f};
    float period[] = {20.0f, 5.0f, 10.0f};
    float util[N];
    float total    = 0.0f;

    for (int i = 0; i < N; i++) {
        util[i] = exec[i] / period[i];   /* utilisation de la tache i */
        total  += util[i];
        printf("Utilisation T%d: %.2f\n", i + 1, util[i]);
    }

    printf("Utilisation totale: %.2f\n", total);
    printf("EDF faisable: %s\n", total <= 1.0f ? "oui" : "non");
    return 0;
}
